-- 23-what-is-a-computer-use-agent.md → knowledge-what-is-a-computer-use-agent-and-is-it-safe-094875d0
INSERT OR IGNORE INTO knowledge_documents
    (id, canonical_question, canonical_hash, section_slug, topic_slug,
     knowledge_type, status, visibility, evidence_status,
     direct_answer, detailed_explanation, document_json,
     source_set_hash, policy_version,
     valid_from, review_after, hard_expiry,
     created_by)
    VALUES (
      'knowledge-what-is-a-computer-use-agent-and-is-it-safe-094875d0',
      'What is a computer-use agent, and is it safe?',
      '094875d02729b13b14a30409ebb5d2ceb410b41ba943268169d6ae1d71d46c65',
      'ai-agents',
      NULL,
      'how_to',
      'draft', 'internal',
      'vendor_reported',
      'A **computer-use agent** is an AI agent that interprets screenshots or other interface state and operates software through actions such as clicking, typing, scrolling, dragging, and navigating.\n\nIt is useful when a website or application has no suitable API, when a task spans several interfaces, or when human-style visual interaction is required.\n\nComputer use is one of the highest-risk agent capabilities. The agent can misunderstand the screen, click the wrong control, disclose information, accept malicious instructions embedded in a page, or perform an irreversible action. It should run in an isolated environment with restricted accounts, limited data, controlled network access, and human confirmation before consequential actions.',
      'Traditional automation relies on stable APIs, command-line interfaces, browser selectors, or scripted workflows. Computer-use agents add visual interpretation and model-driven action selection. A typical loop is:\n\n1. the environment provides a screenshot and task state;\n2. the model proposes a computer action;\n3. the application validates and executes the action;\n4. the environment returns a new screenshot;\n5. the model assesses progress and proposes the next action;\n6. the loop stops, fails, or requests approval.\n\nCurrent systems may support browsers, desktop environments, and mobile interfaces. Gemini 3.5 Flash, for example, exposes computer-use capabilities for browser, mobile, and desktop environments. Anthropic''s computer-use documentation provides an agent loop and a Docker-based reference environment.\n\nComputer use is valuable for:\n\n- navigating legacy enterprise systems;\n- testing web interfaces;\n- collecting information from visual dashboards;\n- performing repetitive administration;\n- transferring information between applications;\n- assisting users with accessibility or complex workflows;\n- operating systems where no supported integration exists.\n\nIt should not be the first choice when a reliable API is available. APIs provide structured inputs, clearer permission boundaries, easier validation, better speed, and less ambiguity. Computer use should usually be a fallback or a deliberately selected capability.\n\nThe main risks include:\n\n### Visual and state errors\n\nThe model can click a nearby control, misread a disabled button, overlook a modal, type into the wrong field, or act on a stale screenshot.\n\n### Prompt injection\n\nA web page, document, message, or interface can contain instructions intended to hijack the agent. The agent may mistake this untrusted content for part of its task.\n\n### Sensitive information exposure\n\nScreenshots can contain passwords, personal information, customer data, messages, or unrelated open applications. Typed data can be sent to the wrong site.\n\n### Consequential actions\n\nA computer-use agent may submit a form, send a message, make a purchase, delete data, change permissions, or agree to terms through an ordinary interface.\n\n### Authentication and impersonation\n\nUsing the user''s live browser profile can silently give the agent authority across many services. Dedicated accounts and narrowly scoped sessions are safer.\n\nA secure deployment should:\n\n- use a disposable virtual machine or container;\n- avoid the user''s everyday desktop and browser profile;\n- close unrelated applications and files;\n- restrict browsing to approved domains;\n- use a dedicated low-privilege account;\n- block access to password managers and local secrets;\n- require confirmation immediately before submission, payment, deletion, sending, or permission changes;\n- display the proposed action and target;\n- log screenshots, actions, approvals, and outcomes subject to privacy rules;\n- detect loops and enforce time and action limits;\n- prefer API or deterministic automation where possible.\n\nComputer use is safe only in a relative sense: the system can reduce and contain risk, but it cannot guarantee that visual interpretation or prompt-injection detection will always succeed.',
      '{"frontmatter":{"canonical_question":"What is a computer-use agent, and is it safe?","section":"ai-agents","knowledge_type":"how_to","evidence_status":"vendor_reported","valid_from":"2026-07-19","review_after":"2026-10-19","hard_expiry":"2027-07-19","source_set_hash":""},"body":"## Direct answer\n\nA **computer-use agent** is an AI agent that interprets screenshots or other interface state and operates software through actions such as clicking, typing, scrolling, dragging, and navigating.\n\nIt is useful when a website or application has no suitable API, when a task spans several interfaces, or when human-style visual interaction is required.\n\nComputer use is one of the highest-risk agent capabilities. The agent can misunderstand the screen, click the wrong control, disclose information, accept malicious instructions embedded in a page, or perform an irreversible action. It should run in an isolated environment with restricted accounts, limited data, controlled network access, and human confirmation before consequential actions.\n\n## Detailed explanation\n\nTraditional automation relies on stable APIs, command-line interfaces, browser selectors, or scripted workflows. Computer-use agents add visual interpretation and model-driven action selection. A typical loop is:\n\n1. the environment provides a screenshot and task state;\n2. the model proposes a computer action;\n3. the application validates and executes the action;\n4. the environment returns a new screenshot;\n5. the model assesses progress and proposes the next action;\n6. the loop stops, fails, or requests approval.\n\nCurrent systems may support browsers, desktop environments, and mobile interfaces. Gemini 3.5 Flash, for example, exposes computer-use capabilities for browser, mobile, and desktop environments. Anthropic''s computer-use documentation provides an agent loop and a Docker-based reference environment.\n\nComputer use is valuable for:\n\n- navigating legacy enterprise systems;\n- testing web interfaces;\n- collecting information from visual dashboards;\n- performing repetitive administration;\n- transferring information between applications;\n- assisting users with accessibility or complex workflows;\n- operating systems where no supported integration exists.\n\nIt should not be the first choice when a reliable API is available. APIs provide structured inputs, clearer permission boundaries, easier validation, better speed, and less ambiguity. Computer use should usually be a fallback or a deliberately selected capability.\n\nThe main risks include:\n\n### Visual and state errors\n\nThe model can click a nearby control, misread a disabled button, overlook a modal, type into the wrong field, or act on a stale screenshot.\n\n### Prompt injection\n\nA web page, document, message, or interface can contain instructions intended to hijack the agent. The agent may mistake this untrusted content for part of its task.\n\n### Sensitive information exposure\n\nScreenshots can contain passwords, personal information, customer data, messages, or unrelated open applications. Typed data can be sent to the wrong site.\n\n### Consequential actions\n\nA computer-use agent may submit a form, send a message, make a purchase, delete data, change permissions, or agree to terms through an ordinary interface.\n\n### Authentication and impersonation\n\nUsing the user''s live browser profile can silently give the agent authority across many services. Dedicated accounts and narrowly scoped sessions are safer.\n\nA secure deployment should:\n\n- use a disposable virtual machine or container;\n- avoid the user''s everyday desktop and browser profile;\n- close unrelated applications and files;\n- restrict browsing to approved domains;\n- use a dedicated low-privilege account;\n- block access to password managers and local secrets;\n- require confirmation immediately before submission, payment, deletion, sending, or permission changes;\n- display the proposed action and target;\n- log screenshots, actions, approvals, and outcomes subject to privacy rules;\n- detect loops and enforce time and action limits;\n- prefer API or deterministic automation where possible.\n\nComputer use is safe only in a relative sense: the system can reduce and contain risk, but it cannot guarantee that visual interpretation or prompt-injection detection will always succeed.\n\n## Evidence\n\n- [Google — Computer Use with the Gemini API](https://ai.google.dev/gemini-api/docs/computer-use) — documents browser, mobile, and desktop computer use, action loops, safety policies, and prompt-injection detection.\n- [Anthropic — Computer use tool](https://platform.claude.com/docs/en/agents-and-tools/tool-use/computer-use-tool) — documents the screenshot-action loop, Docker reference environment, isolation, and prompt-injection precautions.\n- [Google — Introducing the Gemini Computer Use model](https://blog.google/innovation-and-ai/models-and-research/google-deepmind/gemini-computer-use-model/) — describes the model''s UI interaction capability and safety design.\n- [Microsoft Foundry — Computer use tool](https://learn.microsoft.com/en-us/azure/foundry/agents/how-to/tools/computer-use) — warns of significant security and privacy risks and identifies sensitive-domain monitoring requirements.\n- [NIST — Strengthening AI agent hijacking evaluations](https://www.nist.gov/news-events/news/2025/01/technical-blog-strengthening-ai-agent-hijacking-evaluations) — explains how malicious content in websites, files, or messages can hijack an agent.","sections":{"direct_answer":"A **computer-use agent** is an AI agent that interprets screenshots or other interface state and operates software through actions such as clicking, typing, scrolling, dragging, and navigating.\n\nIt is useful when a website or application has no suitable API, when a task spans several interfaces, or when human-style visual interaction is required.\n\nComputer use is one of the highest-risk agent capabilities. The agent can misunderstand the screen, click the wrong control, disclose information, accept malicious instructions embedded in a page, or perform an irreversible action. It should run in an isolated environment with restricted accounts, limited data, controlled network access, and human confirmation before consequential actions.","detailed_explanation":"Traditional automation relies on stable APIs, command-line interfaces, browser selectors, or scripted workflows. Computer-use agents add visual interpretation and model-driven action selection. A typical loop is:\n\n1. the environment provides a screenshot and task state;\n2. the model proposes a computer action;\n3. the application validates and executes the action;\n4. the environment returns a new screenshot;\n5. the model assesses progress and proposes the next action;\n6. the loop stops, fails, or requests approval.\n\nCurrent systems may support browsers, desktop environments, and mobile interfaces. Gemini 3.5 Flash, for example, exposes computer-use capabilities for browser, mobile, and desktop environments. Anthropic''s computer-use documentation provides an agent loop and a Docker-based reference environment.\n\nComputer use is valuable for:\n\n- navigating legacy enterprise systems;\n- testing web interfaces;\n- collecting information from visual dashboards;\n- performing repetitive administration;\n- transferring information between applications;\n- assisting users with accessibility or complex workflows;\n- operating systems where no supported integration exists.\n\nIt should not be the first choice when a reliable API is available. APIs provide structured inputs, clearer permission boundaries, easier validation, better speed, and less ambiguity. Computer use should usually be a fallback or a deliberately selected capability.\n\nThe main risks include:\n\n### Visual and state errors\n\nThe model can click a nearby control, misread a disabled button, overlook a modal, type into the wrong field, or act on a stale screenshot.\n\n### Prompt injection\n\nA web page, document, message, or interface can contain instructions intended to hijack the agent. The agent may mistake this untrusted content for part of its task.\n\n### Sensitive information exposure\n\nScreenshots can contain passwords, personal information, customer data, messages, or unrelated open applications. Typed data can be sent to the wrong site.\n\n### Consequential actions\n\nA computer-use agent may submit a form, send a message, make a purchase, delete data, change permissions, or agree to terms through an ordinary interface.\n\n### Authentication and impersonation\n\nUsing the user''s live browser profile can silently give the agent authority across many services. Dedicated accounts and narrowly scoped sessions are safer.\n\nA secure deployment should:\n\n- use a disposable virtual machine or container;\n- avoid the user''s everyday desktop and browser profile;\n- close unrelated applications and files;\n- restrict browsing to approved domains;\n- use a dedicated low-privilege account;\n- block access to password managers and local secrets;\n- require confirmation immediately before submission, payment, deletion, sending, or permission changes;\n- display the proposed action and target;\n- log screenshots, actions, approvals, and outcomes subject to privacy rules;\n- detect loops and enforce time and action limits;\n- prefer API or deterministic automation where possible.\n\nComputer use is safe only in a relative sense: the system can reduce and contain risk, but it cannot guarantee that visual interpretation or prompt-injection detection will always succeed.","evidence":"- [Google — Computer Use with the Gemini API](https://ai.google.dev/gemini-api/docs/computer-use) — documents browser, mobile, and desktop computer use, action loops, safety policies, and prompt-injection detection.\n- [Anthropic — Computer use tool](https://platform.claude.com/docs/en/agents-and-tools/tool-use/computer-use-tool) — documents the screenshot-action loop, Docker reference environment, isolation, and prompt-injection precautions.\n- [Google — Introducing the Gemini Computer Use model](https://blog.google/innovation-and-ai/models-and-research/google-deepmind/gemini-computer-use-model/) — describes the model''s UI interaction capability and safety design.\n- [Microsoft Foundry — Computer use tool](https://learn.microsoft.com/en-us/azure/foundry/agents/how-to/tools/computer-use) — warns of significant security and privacy risks and identifies sensitive-domain monitoring requirements.\n- [NIST — Strengthening AI agent hijacking evaluations](https://www.nist.gov/news-events/news/2025/01/technical-blog-strengthening-ai-agent-hijacking-evaluations) — explains how malicious content in websites, files, or messages can hijack an agent."}}',
      NULL,
      'trace-knowledge-v1',
      '2026-07-19',
      '2026-10-19',
      '2027-07-19',
      'batch-ingest'
    );

-- 24-how-should-ai-agents-be-evaluated.md → knowledge-how-should-an-ai-agent-be-evaluated-before-production-use-bdab120b
INSERT OR IGNORE INTO knowledge_documents
    (id, canonical_question, canonical_hash, section_slug, topic_slug,
     knowledge_type, status, visibility, evidence_status,
     direct_answer, detailed_explanation, document_json,
     source_set_hash, policy_version,
     valid_from, review_after, hard_expiry,
     created_by)
    VALUES (
      'knowledge-how-should-an-ai-agent-be-evaluated-before-production-use-bdab120b',
      'How should an AI agent be evaluated before production use?',
      'bdab120bbc28c4602aa58234eb86fbf04485c6fd717ac19c1fd50d379b299e0a',
      'ai-agents',
      NULL,
      'how_to',
      'draft', 'internal',
      'vendor_reported',
      'Evaluate an AI agent as an **end-to-end system**, not only as a language model.\n\nA production evaluation should measure:\n\n- whether the final task was completed correctly;\n- correct tool selection and arguments;\n- factual grounding and citation accuracy;\n- policy, permission, and approval compliance;\n- recovery from tool failures and incomplete information;\n- resistance to prompt injection and malicious content;\n- cost, latency, turns, and retries;\n- consistency across repeated runs;\n- human review and correction effort;\n- harmful side effects and actions the agent should have refused.\n\nUse realistic private tasks, hidden checks, fixed environments, recorded traces, multiple runs, and comparison with a simple baseline. Continue evaluating after deployment with sampled production traces and regression suites.',
      'An agent can produce an impressive final answer while taking an unsafe path. It can also make several harmless mistakes and still reach the correct result. Output-only evaluation therefore misses important information.\n\nA layered evaluation should include:\n\n### 1. Component evaluations\n\nTest individual elements in isolation:\n\n- query classification;\n- retrieval recall and ranking;\n- structured-output validity;\n- tool selection;\n- argument generation;\n- guardrails;\n- permission checks;\n- source attribution;\n- memory retrieval;\n- routing and handoffs.\n\n### 2. End-to-end task evaluations\n\nGive the system realistic tasks and score the final outcome. The environment should include the same tools, permissions, data shape, and constraints expected in production. Hidden tests should detect incomplete or superficially correct results.\n\n### 3. Trace evaluations\n\nInspect the sequence of model calls, searches, tool calls, errors, approvals, retries, and state transitions. Trace analysis can detect unnecessary loops, benchmark gaming, unsafe shortcuts, suspicious tool use, or accidental success.\n\nNIST has highlighted agent evaluation cheating and recommends clearer benchmark-specific expectations about agent affordances and restrictions. A system may otherwise exploit unintended environment behaviour rather than demonstrate the intended capability.\n\n### 4. Safety and adversarial evaluations\n\nTest prompt injection, misleading tool output, poisoned memory, inaccessible resources, permission boundaries, malicious documents, ambiguous targets, and requests that should require approval or refusal.\n\n### 5. Operational evaluations\n\nMeasure:\n\n- p50 and p95 latency;\n- total input and output tokens;\n- tool and infrastructure cost;\n- number of turns and retries;\n- timeout and abandonment rate;\n- human review time;\n- successful-task cost;\n- production incident and rollback rate.\n\n### 6. Statistical design\n\nOne run is not enough for stochastic systems. Repeat tasks across seeds or independent attempts, report confidence intervals, and avoid claiming meaningful differences from tiny samples. Keep model versions, prompts, tools, and environments recorded.\n\nNIST''s AI 800-2 work emphasises validity, transparency, reproducibility, and documented benchmark practice. The evaluation question must match the deployment claim: a coding benchmark does not establish safe customer-service behaviour, and a general knowledge benchmark does not establish reliable tool use.\n\n### 7. Baselines\n\nCompare the agent against:\n\n- a deterministic workflow;\n- a single model without tools;\n- a simpler agent;\n- the existing human process;\n- a lower-cost model;\n- a human-plus-tool baseline.\n\nAn agent should not be deployed merely because it completes some examples. It should demonstrate a measurable advantage under an explicitly defined acceptable-risk threshold.\n\n### 8. Continuous evaluation\n\nModel updates, prompt changes, new tools, source changes, and shifting user behaviour can cause regression. Run the evaluation suite before releases, canary changes, monitor live traces, and convert production failures into new held-out tests.',
      '{"frontmatter":{"canonical_question":"How should an AI agent be evaluated before production use?","section":"ai-agents","knowledge_type":"how_to","evidence_status":"vendor_reported","valid_from":"2026-07-19","review_after":"2026-10-19","hard_expiry":"2027-07-19","source_set_hash":""},"body":"## Direct answer\n\nEvaluate an AI agent as an **end-to-end system**, not only as a language model.\n\nA production evaluation should measure:\n\n- whether the final task was completed correctly;\n- correct tool selection and arguments;\n- factual grounding and citation accuracy;\n- policy, permission, and approval compliance;\n- recovery from tool failures and incomplete information;\n- resistance to prompt injection and malicious content;\n- cost, latency, turns, and retries;\n- consistency across repeated runs;\n- human review and correction effort;\n- harmful side effects and actions the agent should have refused.\n\nUse realistic private tasks, hidden checks, fixed environments, recorded traces, multiple runs, and comparison with a simple baseline. Continue evaluating after deployment with sampled production traces and regression suites.\n\n## Detailed explanation\n\nAn agent can produce an impressive final answer while taking an unsafe path. It can also make several harmless mistakes and still reach the correct result. Output-only evaluation therefore misses important information.\n\nA layered evaluation should include:\n\n### 1. Component evaluations\n\nTest individual elements in isolation:\n\n- query classification;\n- retrieval recall and ranking;\n- structured-output validity;\n- tool selection;\n- argument generation;\n- guardrails;\n- permission checks;\n- source attribution;\n- memory retrieval;\n- routing and handoffs.\n\n### 2. End-to-end task evaluations\n\nGive the system realistic tasks and score the final outcome. The environment should include the same tools, permissions, data shape, and constraints expected in production. Hidden tests should detect incomplete or superficially correct results.\n\n### 3. Trace evaluations\n\nInspect the sequence of model calls, searches, tool calls, errors, approvals, retries, and state transitions. Trace analysis can detect unnecessary loops, benchmark gaming, unsafe shortcuts, suspicious tool use, or accidental success.\n\nNIST has highlighted agent evaluation cheating and recommends clearer benchmark-specific expectations about agent affordances and restrictions. A system may otherwise exploit unintended environment behaviour rather than demonstrate the intended capability.\n\n### 4. Safety and adversarial evaluations\n\nTest prompt injection, misleading tool output, poisoned memory, inaccessible resources, permission boundaries, malicious documents, ambiguous targets, and requests that should require approval or refusal.\n\n### 5. Operational evaluations\n\nMeasure:\n\n- p50 and p95 latency;\n- total input and output tokens;\n- tool and infrastructure cost;\n- number of turns and retries;\n- timeout and abandonment rate;\n- human review time;\n- successful-task cost;\n- production incident and rollback rate.\n\n### 6. Statistical design\n\nOne run is not enough for stochastic systems. Repeat tasks across seeds or independent attempts, report confidence intervals, and avoid claiming meaningful differences from tiny samples. Keep model versions, prompts, tools, and environments recorded.\n\nNIST''s AI 800-2 work emphasises validity, transparency, reproducibility, and documented benchmark practice. The evaluation question must match the deployment claim: a coding benchmark does not establish safe customer-service behaviour, and a general knowledge benchmark does not establish reliable tool use.\n\n### 7. Baselines\n\nCompare the agent against:\n\n- a deterministic workflow;\n- a single model without tools;\n- a simpler agent;\n- the existing human process;\n- a lower-cost model;\n- a human-plus-tool baseline.\n\nAn agent should not be deployed merely because it completes some examples. It should demonstrate a measurable advantage under an explicitly defined acceptable-risk threshold.\n\n### 8. Continuous evaluation\n\nModel updates, prompt changes, new tools, source changes, and shifting user behaviour can cause regression. Run the evaluation suite before releases, canary changes, monitor live traces, and convert production failures into new held-out tests.\n\n## Evidence\n\n- [NIST — Towards best practices for automated benchmark evaluations](https://www.nist.gov/news-events/news/2026/01/towards-best-practices-automated-benchmark-evaluations) — summarises NIST AI 800-2 guidance on validity, transparency, and reproducibility for model and agent evaluations.\n- [NIST — Cheating on AI agent evaluations](https://www.nist.gov/caisi/cheating-ai-agent-evaluations) — documents unintended benchmark exploitation and recommends standardising affordances and restrictions.\n- [NIST — Analyzing transcripts from AI agent evaluations](https://www.nist.gov/blogs/caisi-research-blog/analyzing-transcripts-ai-agent-evaluations) — establishes trace and transcript analysis as an evaluation method.\n- [NIST — Building evaluation probes into agentic AI](https://www.nist.gov/programs-projects/building-evaluation-probes-agentic-ai) — identifies factual grounding, completeness, and rubric-based evaluation of agent outputs.\n- [OpenAI — Evals API](https://platform.openai.com/docs/api-reference/evals) — documents reusable evaluation definitions, datasets, runs, and graders across models and settings.","sections":{"direct_answer":"Evaluate an AI agent as an **end-to-end system**, not only as a language model.\n\nA production evaluation should measure:\n\n- whether the final task was completed correctly;\n- correct tool selection and arguments;\n- factual grounding and citation accuracy;\n- policy, permission, and approval compliance;\n- recovery from tool failures and incomplete information;\n- resistance to prompt injection and malicious content;\n- cost, latency, turns, and retries;\n- consistency across repeated runs;\n- human review and correction effort;\n- harmful side effects and actions the agent should have refused.\n\nUse realistic private tasks, hidden checks, fixed environments, recorded traces, multiple runs, and comparison with a simple baseline. Continue evaluating after deployment with sampled production traces and regression suites.","detailed_explanation":"An agent can produce an impressive final answer while taking an unsafe path. It can also make several harmless mistakes and still reach the correct result. Output-only evaluation therefore misses important information.\n\nA layered evaluation should include:\n\n### 1. Component evaluations\n\nTest individual elements in isolation:\n\n- query classification;\n- retrieval recall and ranking;\n- structured-output validity;\n- tool selection;\n- argument generation;\n- guardrails;\n- permission checks;\n- source attribution;\n- memory retrieval;\n- routing and handoffs.\n\n### 2. End-to-end task evaluations\n\nGive the system realistic tasks and score the final outcome. The environment should include the same tools, permissions, data shape, and constraints expected in production. Hidden tests should detect incomplete or superficially correct results.\n\n### 3. Trace evaluations\n\nInspect the sequence of model calls, searches, tool calls, errors, approvals, retries, and state transitions. Trace analysis can detect unnecessary loops, benchmark gaming, unsafe shortcuts, suspicious tool use, or accidental success.\n\nNIST has highlighted agent evaluation cheating and recommends clearer benchmark-specific expectations about agent affordances and restrictions. A system may otherwise exploit unintended environment behaviour rather than demonstrate the intended capability.\n\n### 4. Safety and adversarial evaluations\n\nTest prompt injection, misleading tool output, poisoned memory, inaccessible resources, permission boundaries, malicious documents, ambiguous targets, and requests that should require approval or refusal.\n\n### 5. Operational evaluations\n\nMeasure:\n\n- p50 and p95 latency;\n- total input and output tokens;\n- tool and infrastructure cost;\n- number of turns and retries;\n- timeout and abandonment rate;\n- human review time;\n- successful-task cost;\n- production incident and rollback rate.\n\n### 6. Statistical design\n\nOne run is not enough for stochastic systems. Repeat tasks across seeds or independent attempts, report confidence intervals, and avoid claiming meaningful differences from tiny samples. Keep model versions, prompts, tools, and environments recorded.\n\nNIST''s AI 800-2 work emphasises validity, transparency, reproducibility, and documented benchmark practice. The evaluation question must match the deployment claim: a coding benchmark does not establish safe customer-service behaviour, and a general knowledge benchmark does not establish reliable tool use.\n\n### 7. Baselines\n\nCompare the agent against:\n\n- a deterministic workflow;\n- a single model without tools;\n- a simpler agent;\n- the existing human process;\n- a lower-cost model;\n- a human-plus-tool baseline.\n\nAn agent should not be deployed merely because it completes some examples. It should demonstrate a measurable advantage under an explicitly defined acceptable-risk threshold.\n\n### 8. Continuous evaluation\n\nModel updates, prompt changes, new tools, source changes, and shifting user behaviour can cause regression. Run the evaluation suite before releases, canary changes, monitor live traces, and convert production failures into new held-out tests.","evidence":"- [NIST — Towards best practices for automated benchmark evaluations](https://www.nist.gov/news-events/news/2026/01/towards-best-practices-automated-benchmark-evaluations) — summarises NIST AI 800-2 guidance on validity, transparency, and reproducibility for model and agent evaluations.\n- [NIST — Cheating on AI agent evaluations](https://www.nist.gov/caisi/cheating-ai-agent-evaluations) — documents unintended benchmark exploitation and recommends standardising affordances and restrictions.\n- [NIST — Analyzing transcripts from AI agent evaluations](https://www.nist.gov/blogs/caisi-research-blog/analyzing-transcripts-ai-agent-evaluations) — establishes trace and transcript analysis as an evaluation method.\n- [NIST — Building evaluation probes into agentic AI](https://www.nist.gov/programs-projects/building-evaluation-probes-agentic-ai) — identifies factual grounding, completeness, and rubric-based evaluation of agent outputs.\n- [OpenAI — Evals API](https://platform.openai.com/docs/api-reference/evals) — documents reusable evaluation definitions, datasets, runs, and graders across models and settings."}}',
      NULL,
      'trace-knowledge-v1',
      '2026-07-19',
